artifacts.model_fusion_raw_response:
package Integer_Toy
public 
   with Base_Types;

system A
	features
		Input: in data port Base_Types::Integer;
		Output: out data port Base_Types::Integer;
end A ; 

system B
	features
		Input: in data port Base_Types::Integer;
		Output: out data port Base_Types::Integer;
end B ; 

system C
	features
		Input1: in data port Base_Types::Integer;
		Input2: in data port Base_Types::Integer;
		Output: out data port Base_Types::Integer;
end C ; 

system top_level
	features
		Input: in data port Base_Types::Integer;
		Output: out data port Base_Types::Integer;
annex agree {**
  assume "input_bound": Input < 10;
  guarantee "mode_non_negative": mode >= 0;
  guarantee "output_bound": Output < 50;
  assign "input_forward": A_sub.Input = Input;
  assign "a_to_b_c": B_sub.Input = A_sub.Output;
  assign "a_to_c": C_sub.Input_1 = A_sub.Output;
  assign "b_to_c": C_sub.Input_2 = B_sub.Output;
  assign "c_to_output": Output = C_sub.Output;
  assign "mode_assignment": mode = C_sub.mode;
**};
end top_level;

system implementation top_level.Impl
	subcomponents
		A_sub : system A ; 
		B_sub : system B ; 
		C_sub : system C ; 
	connections
		IN_TO_A : port Input -> A_sub.Input {Communication_Properties::Timing => immediate;};
		A_TO_B : port A_sub.Output -> B_sub.Input {Communication_Properties::Timing => immediate;};
		A_TO_C : port A_sub.Output -> C_sub.Input1 {Communication_Properties::Timing => immediate;};
		B_TO_C : port B_sub.Output -> C_sub.Input2 {Communication_Properties::Timing => immediate;};
		C_TO_Output : port C_sub.Output -> Output {Communication_Properties::Timing => immediate;};

annex agree {**

  assume "input_bound": Input < 10;

  guarantee "mode_non_negative": mode >= 0;

  guarantee "output_bound": Output < 50;

  assign "input_forward": A_sub.Input = Input;

  assign "a_to_b_c": B_sub.Input = A_sub.Output;

  assign "a_to_c": C_sub.Input_1 = A_sub.Output;

  assign "b_to_c": C_sub.Input_2 = B_sub.Output;

  assign "c_to_output": Output = C_sub.Output;

  assign "mode_assignment": mode = C_sub.mode;

**};

end top_level.Impl;

end Integer_Toy;

